```bash
#!/bin/bash

# Load Bob's private key
openssl rsa -in private_key.pem -out private_key.pem -inform PEM -outform PEM

# Decrypt the symmetric key
openssl rsa -in private_key.pem -in encrypted_symmetric_key.pem -out decrypted_symmetric_key.pem -inform PEM -outform PEM -decrypt

# Decrypt the file using the recovered symmetric key
openssl enc -aes-256-cbc -d -in encrypted_file.txt -out decrypted_file.txt -kfile decrypted_symmetric_key.pem
```

