# Load Bob's private key
openssl rsa -in bobs_private_key.pem -inform PEM -out bobs_private_key.bin -outform DER

# Decrypt the symmetric key using Bob's private key
openssl rsautl decrypt -in symmetric_key.enc -inkey bobs_private_key.bin -raw -binary -out symmetric_key.bin

# Decrypt the file using the recovered symmetric key
openssl enc -aes-256-cbc -d -in encrypted_file.bin -inkey symmetric_key.bin -out decrypted_file.bin
```

